import { useEffect, useState, useCallback } from 'react';

/** Homepage sections (below hero): animate when more of the block is in view — feels more gradual on scroll. */
export const HOME_SECTION_IN_VIEW_THRESHOLD = 0.18;
export const HOME_SECTION_IN_VIEW_ROOT_MARGIN = '0px 0px -16% 0px';

/** Hero: slightly earlier trigger so first paint still feels responsive. */
export const HOME_HERO_IN_VIEW_THRESHOLD = 0.1;
export const HOME_HERO_IN_VIEW_ROOT_MARGIN = '0px 0px -6% 0px';

/**
 * Observes an element; sets visible to true once it enters the viewport.
 * Disconnects after first intersection (default) to avoid extra work.
 * Uses a callback ref so observation still works when the node mounts after
 * async work (e.g. conditional render after fetch).
 */
export function useInView(threshold = 0.12, rootMargin = '0px 0px -8% 0px') {
  const [node, setNode] = useState(null);
  const [visible, setVisible] = useState(false);

  const setRef = useCallback((el) => {
    setNode(el);
  }, []);

  useEffect(() => {
    if (!node || visible) return undefined;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold, rootMargin }
    );

    observer.observe(node);
    return () => observer.disconnect();
  }, [node, threshold, rootMargin, visible]);

  return [setRef, visible];
}
